// Picks a deterministic quote for a given date string (so it's the same all day)
window.quoteOfDay = function (dateStr) {
  const q = window.DAILY_QUOTES;
  if (!dateStr) return q[0];
  let h = 0;
  for (let i = 0; i < dateStr.length; i++) h = (h * 31 + dateStr.charCodeAt(i)) >>> 0;
  return q[h % q.length];
};

